};

struct VerticalDWTBandWriter {
    bool CHECKED;
    int next;
};

__device__ int saveAndUpdate(struct VerticalDWTBandWriter *writer, bool CHECK, struct VerticalDWTBandIO *bandIO, int *const output, int *item, int *stride) {
    writer->CHECKED = CHECK;
    if ((!writer->CHECKED) || (writer->next != bandIO->end)) {
        output[writer->next] = *item;
        writer->next += *stride;
    }
    return writer->next;
}

__device__ void clear_BandWriter(struct VerticalDWTBandWriter *writer, struct VerticalDWTBandIO *bandIO) {
    bandIO->end = 0;
    bandIO->strideHighToLow = 0;
    bandIO->strideLowToHigh = 0;
    writer->next = 0;
}

__device__ void init_BandWriter(struct VerticalDWTBandWriter *writer, struct VerticalDWTBandIO *bandIO, const int imageSizeX, const int imageSizeY, const int firstX, const int firstY) {
    if (firstX < imageSizeX) {
        writer->next = initialize_BandIO(bandIO, imageSizeX, imageSizeY, firstX, firstY);
    } else {
        clear_BandWriter(writer, bandIO);
    }
}

__device__ int writeLowInto(struct VerticalDWTBandWriter *writer, struct VerticalDWTBandIO *bandIO, int *const output, int *primary) {
    return saveAndUpdate(writer, writer->CHECKED, bandIO, output, primary, &(bandIO->strideLowToHigh));
}

__device__ int writeHighInto(struct VerticalDWTBandWriter *writer, struct VerticalDWTBandIO *bandIO, int *const output, int *other) {
    return saveAndUpdate(writer, writer->CHECKED, bandIO, output, other, &(bandIO->strideHighToLow));
}

