cudaContext CreateContext() {
    cudaContext context = NULL;
    cudaUint platformIdCount = 0;
    cudaInt errNum;

    cudaGetPlatformIDs(0, NULL, &platformIdCount);

    std::vector<cudaPlatformId> platformIds(platformIdCount);
    cudaGetPlatformIDs(platformIdCount, platformIds.data(), NULL);

    cudaContextProperties contextProperties[] = {
        CUDA_CONTEXT_PLATFORM,
        (cudaContextProperties)platformIds[platform],
        0
    };
    context = cudaCreateContextFromType(contextProperties, CUDA_DEVICE_TYPE_GPU, NULL, NULL, &errNum);
    if (errNum != CUDA_SUCCESS) {
        std::cout << "Could not create GPU context, trying CPU..." << std::endl;
        context = cudaCreateContextFromType(contextProperties, CUDA_DEVICE_TYPE_CPU, NULL, NULL, &errNum);
        if (errNum != CUDA_SUCCESS) {
            std::cerr << "Failed to create a CUDA GPU or CPU context." << std::endl;
            return NULL;
        }
    }

    return context;
}

cudaCommandQueue CreateCommandQueue(cudaContext context, cudaDevice *cldevice) {
    cudaInt errNum;
    cudaDevice *cldevices;
    cudaCommandQueue commandQueue = NULL;
    size_t deviceBufferSize = -1;

    errNum = cudaGetContextInfo(context, CUDA_CONTEXT_DEVICES, 0, NULL, &deviceBufferSize);
    if (errNum != CUDA_SUCCESS) {
        std::cerr << "Failed call to cudaGetContextInfo(...,CUDA_CONTEXT_DEVICES,...)";
        return NULL;
    }

    if (deviceBufferSize <= 0) {
        std::cerr << "No devices available.";
        return NULL;
    }

    cldevices = new cudaDevice[deviceBufferSize / sizeof(cudaDevice)];
    errNum = cudaGetContextInfo(context, CUDA_CONTEXT_DEVICES, deviceBufferSize, cldevices, NULL);
    if (errNum != CUDA_SUCCESS) {
        delete[] cldevices;
        std::cerr << "Failed to get device IDs";
        return NULL;
    }

#ifdef TIMING
    commandQueue = cudaCreateCommandQueue(context, cldevices[device], CUDA_QUEUE_PROFILING_ENABLE, NULL);
#else
    commandQueue = cudaCreateCommandQueue(context, cldevices[device], 0, NULL);
#endif
    if (commandQueue == NULL) {
        delete[] cldevices;
        std::cerr << "Failed to create commandQueue for device ";
        return NULL;
    }

    *cldevice = cldevices[device];
    delete[] cldevices;
    return commandQueue;
}

cudaProgram CreateProgram(cudaContext context, cudaDevice cldevice, const char *fileName) {
    cudaInt errNum;
    cudaProgram program;

    std::ifstream kernelFile(fileName, std::ios::in);
    if (!kernelFile.is_open()) {
        std::cerr << "Failed to open file for reading: " << fileName << std::endl;
        return NULL;
    }

    std::ostringstream oss;
    oss << kernelFile.rdbuf();

    std::string srcStdStr = oss.str();
    const char *srcStr = srcStdStr.c_str();
    program = cudaCreateProgramWithSource(context, 1, (const char **)&srcStr, NULL, NULL);
    if (program == NULL) {
        std::cerr << "Failed to create CUDA program from source." << std::endl;
        return NULL;
    }

    errNum = cudaBuildProgram(program, 0, NULL, NULL, NULL, NULL);
    if (errNum != CUDA_SUCCESS) {
        char buildLog[16384];
        cudaGetProgramBuildInfo(program, cldevice, CUDA_PROGRAM_BUILD_LOG, sizeof(buildLog), buildLog, NULL);

        std::cerr << "Error in kernel: " << std::endl;
        std::cerr << buildLog;
        cudaReleaseProgram(program);
        return NULL;
    }

    return program;
}

