            pixWidth = atoi(optarg);
            pos = strstr(optarg, "x");
            if (pos == NULL || pixWidth == 0 || (strlen(pos) >= strlen(optarg))) {
                usage();
                return -1;
            }
            pixHeight = atoi(pos + 1);
            break;
        case 'c':
            compCount = atoi(optarg);
            break;
        case 'b':
            bitDepth = atoi(optarg);
            break;
        case 'l':
            dwtLvls = atoi(optarg);
            break;
        case 'd':
            device = atoi(optarg);
            break;
        case 'p':
            platform = atoi(optarg);
            break;
        case 'i':
            strcpy(input_dir, optarg);
            break;
        case 'f':
            forward = 1;
            break;
        case 'r':
            forward = 0;
            break;
        case '9':
            dwt97 = 1;
            break;
        case '5':
            dwt97 = 0;
            break;
        case 'w':
            writeVisual = 1;
            break;
        case 'h':
            usage();
            return 0;
        case '?':
            return -1;
        default:
            usage();
            return -1;
        }
    }
    argc -= optindex;
    argv += optindex;

    if (argc == 0) {
        printf("Please supply src file name\n");
        usage();
        return -1;
    }

    if (pixWidth <= 0 || pixHeight <= 0) {
        printf("Wrong or missing dimensions\n");
        usage();
        return -1;
    }

    if (forward == 0) {
        writeVisual = 0;
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif
    context = CreateContext();
    if (context == NULL) {
        std::cerr << "Failed to create CUDA context." << std::endl;
        return 1;
    }

    commandQueue = CreateCommandQueue(context, &cldevice);
    if (commandQueue == NULL) {
        Cleanup(context, commandQueue, program, kernel);
        return 1;
    }

    program = CreateProgram(context, cldevice, "com_dwt.cl");
    if (program == NULL) {
        printf("fail to create program!!\n");
    }

    c_CopySrcToComponents = cudaCreateKernel(program, "c_CopySrcToComponents", NULL);
    if (c_CopySrcToComponents == NULL) {
        std::cerr << "Failed to create kernel" << std::endl;
    }

    c_CopySrcToComponent = cudaCreateKernel(program, "c_CopySrcToComponent", NULL);
    if (c_CopySrcToComponent == NULL) {
        std::cerr << "Failed to create kernel" << std::endl;
    }

    kl_fdwt53Kernel = cudaCreateKernel(program, "cl_fdwt53Kernel", NULL);
    if (kl_fdwt53Kernel == NULL) {
        std::cerr << "Failed to create kernel\n";
    }
#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    struct dwt *d;
    d = (struct dwt *)malloc(sizeof(struct dwt));
    d->srcImg = NULL;
    d->pixWidth = pixWidth;
    d->pixHeight = pixHeight;
    d->components = compCount;
    d->dwtLvls = dwtLvls;

    d->srcFilename = (char *)malloc(strlen(argv[0]));
    strcpy(d->srcFilename, argv[0]);
    if (argc == 1) {
        d->outFilename = (char *)malloc(strlen(d->srcFilename) + 4);
        strcpy(d->outFilename, d->srcFilename);
        strcpy(d->outFilename + strlen(d->srcFilename), ".dwt");
    } else {
        d->outFilename = strdup(argv[1]);
    }
    char real_filename[100];
    sprintf(real_filename, "%s/%s", input_dir, d->srcFilename);

    printf("\nSource file:\t\t%s\n", real_filename);
    printf(" Dimensions:\t\t%dx%d\n", pixWidth, pixHeight);
    printf(" Components count:\t%d\n", compCount);
    printf(" Bit depth:\t\t%d\n", bitDepth);
    printf(" DWT levels:\t\t%d\n", dwtLvls);
    printf(" Forward transform:\t%d\n", forward);
    printf(" 9/7 transform:\t\t%d\n", dwt97);

    int inputSize = pixWidth * pixHeight * compCount;

    d->srcImg = (unsigned char *)malloc(inputSize);
    if (getImg(real_filename, d->srcImg, inputSize) == -1)
        return -1;

    if (forward == 1) {
        if (dwt97 == 1)
            processDWT<float>(d, forward, writeVisual);
        else
            processDWT<int>(d, forward, writeVisual);
    } else {
        if (dwt97 == 1)
            processDWT<float>(d, forward, writeVisual);
        else
            processDWT<int>(d, forward, writeVisual);
    }

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    Cleanup(context, commandQueue, program, kernel);
    cudaReleaseKernel(c_CopySrcToComponents);
    cudaReleaseKernel(c_CopySrcToComponent);

#ifdef TIMING
    gettimeofday(&tv_total_end, NULL);
    tvsub(&tv_total_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    tvsub(&tv_total_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    free(d->srcFilename);
    free(d->srcImg);
    free(d);

    return 0;
}

